# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import json
import pymysql

def cloud_function(event, context):
    # Extract parameters from the HTTP request
    params = event.get('queryStringParameters', {})
    
    # Database configuration
    db_config = {
        'host': 'your_host',
        'user': 'your_user',
        'password': 'your_password',
        'database': 'your_database'
    }
    
    # Construct dynamic SQL query
    sql = "SELECT * FROM your_table WHERE 1=1"
    
    if 'name' in params:
        sql += f" AND name LIKE '%{params['name']}%'"
    
    if 'age' in params:
        sql += f" AND age = {int(params['age'])}"
    
    # Connect to the database
    connection = pymysql.connect(**db_config)
    try:
        with connection.cursor() as cursor:
            # Execute the query
            cursor.execute(sql)
            result = cursor.fetchall()
            
            # Return the result as JSON
            return {
                'statusCode': 200,
                'body': json.dumps(result, default=str),
                'headers': {'Content-Type': 'application/json'}
            }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)}),
            'headers': {'Content-Type': 'application/json'}
        }
    finally:
        connection.close()